[CmdletBinding()]param([ValidateRange(1024,65535)][int]$Port,[switch]$Uninstall,[string]$Destination=(Join-Path $env:LOCALAPPDATA 'WukongCodexForge'))
$ErrorActionPreference='Stop';$root=Join-Path $Destination 'app';if($Port){if(Test-Path (Join-Path $root 'runtime\injector.mjs')){Push-Location $root;try{node runtime/injector.mjs --restore $Port}finally{Pop-Location}}};if($Uninstall){if(Test-Path $Destination){Remove-Item -LiteralPath $Destination -Recurse -Force};Write-Host 'Managed Wukong Codex Forge files removed. Codex itself was never modified.'}else{Write-Host 'Restore attempted. Close Codex if an existing renderer retains cached styles.'}
